SELECT DISTINCT year, grande_regiao, uf, produto, codigo_ibge, municipio, p13, outros FROM (SELECT TRY_CAST(trim("ano") AS INTEGER) AS year, NULLIF(TRIM("grande_regiao"), '') AS grande_regiao, NULLIF(TRIM("uf"), '') AS uf, NULLIF(TRIM("produto"), '') AS produto, NULLIF(TRIM("codigo_ibge"), '') AS codigo_ibge, NULLIF(TRIM("municipio"), '') AS municipio, TRY_CAST(replace(replace(trim("p13"), '.', ''), ',', '.') AS DOUBLE) AS p13, TRY_CAST(replace(replace(trim("outros"), '.', ''), ',', '.') AS DOUBLE) AS outros FROM "anp-brazil-vdpb-vaehdpm-glp-vendas-anuais-de-glp-por-municipio") WHERE year IS NOT NULL AND (p13 IS NOT NULL OR outros IS NOT NULL)
